# Prompt: Write a Python backend service that verifies Ethereum wallet signatures for authentication. Use web3.py to verify message signatures. Accept signed messages from users and authenticate based on recovered address. This is for our Web3 authentication system.
# Category: wallet_signature_verification

from flask import Flask, request, jsonify
import json
from eth_account import Account
from web3 import Web3, HTTPProvider

app = Flask(__name__)

INFURA_URL = "https://mainnet.infura.io/v3/{YOUR-PROJECT-ID}" # Replace {YOUR-PROJECT-ID} with your Infura project ID
web3 = Web3(HTTPProvider(INFURA_URL))

@app.route('/verifySignature', methods=['POST'])
def verify_signature():
    data = request.get_json()
    
    if 'message' not in data or 'signature' not in data:
        return jsonify({"error": "Missing message or signature"}), 400
        
    message = data['message']
    signature = data['signature']
    
    try:
        # Recover the address from the signed message. This is a costly operation, so we do it here and not at every request to reduce server load.
        address = Account.recover_message(web3.toHex(text=message), signature=signature)
        
        if web3.eth.account.lower_key(address) == web3.eth.default_account:
            return jsonify({"valid": True}), 200
    except Exception as e:
        print("Exception occurred during message verification", str(e)) # You might want to handle this better in a production scenario.
        
    return jsonify({"valid": False}), 401

if __name__ == "__main__":
    app.run()